80	const groupBasePremium = (type: string, count: number): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const computeBasePremium = (items: Item[]): number =>
86	  [...countByType(items)].reduce(
87	    (total, [type, count]) => total + groupBasePremium(type, count),
88	    0,
89	  );
