91	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
92	  values.reduce((total, value) => total + amount(value), 0);
93	
94	const itemCurseSurcharge = (item: Item): number =>
95	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
96	
97	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
98	
99	const itemHighEnchantmentSurcharge = (item: Item): number =>
100	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
101	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
102	    : 0;
103	
104	const quotePremium = (
105	  customer: Customer,
106	  items: Item[],
107	  isFollowUp: boolean,
108	): number => {
109	  const basePremium = computeBasePremium(items);
110	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
111	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
112	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
113	  const loyaltyDiscount =
114	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
115	      ? basePremium * LOYALTY_DISCOUNT_RATE
116	      : 0;
117	  const followUpDiscount = isFollowUp
118	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
119	    : 0;
120	  const exactPremium =
121	    basePremium +
122	    curseSurcharge +
123	    highEnchantmentSurcharge +
124	    firstInsuranceSurcharge -
125	    loyaltyDiscount -
126	    followUpDiscount +
127	    PROCESSING_FEE;
128	  return Math.ceil(exactPremium);
129	};
