149	const findInsuredItem = (insuredItems: Item[], damage: Damage): Item =>
150	  insuredItems.find((item) => item.type === damage.itemType) as Item;
151	
152	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
153	  reimbursementFor(findInsuredItem(insuredItems, damage), damage) - DEDUCTIBLE;
154	
155	const processClaim = (policy: QuoteStep, claim: ClaimStep): ClaimResult => {
156	  const payoutCap =
157	    PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
158	  const payout = sumBy(claim.incident.damages, (damage) =>
159	    damagePayout(policy.items, damage),
160	  );
161	  return { payout, remainingCap: payoutCap - payout };
162	};
